<?php
namespace Tests\Feature;use App\Domain\Hunts\HuntService;use App\Domain\Hunts\Rewards\HuntRewardService;use App\Domain\Hunts\Rewards\HuntRewardStatus;use App\Domain\Hunts\Sessions\HuntingSessionService;use App\Models\Character;use App\Models\Hunt;use App\Models\HuntReward;use App\Models\HuntRewardItem;use App\Models\HuntingSession;use App\Models\MonsterLootEntry;use App\Models\User;use App\Models\Zone;use Carbon\CarbonImmutable;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;class HuntRewardTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);CarbonImmutable::setTestNow('2026-07-12 12:00:00');MonsterLootEntry::query()->update(['drop_chance_basis_points'=>10000,'minimum_quantity'=>1,'maximum_quantity'=>1]);}protected function tearDown():void{CarbonImmutable::setTestNow();parent::tearDown();}private function player(){return Character::factory()->for(User::factory())->create(['base_attack'=>500]);}private function zone(){return Zone::where('code','grey_oak_forest')->first();}
 public function test_victory_creates_pending_reward_lines_and_summary(){$c=$this->player();$service=app(HuntingSessionService::class);$s=HuntingSession::find($service->start($c,$this->zone())->id());$tick=$service->tick($c,$s)->toArray();$this->assertSame(1,HuntReward::count());$this->assertGreaterThan(0,HuntRewardItem::count());$reward=HuntReward::first();$this->assertSame(HuntRewardStatus::PENDING,$reward->status);$this->assertGreaterThan(0,$reward->gold_amount);$this->assertGreaterThan(0,$reward->experience_amount);$this->assertNotNull($tick['generated_reward']);$this->assertSame($reward->gold_amount,$tick['generated_reward']['gold_amount']);$this->assertSame($reward->experience_amount,$tick['generated_reward']['experience_amount']);$this->assertSame(1,$tick['session_pending_rewards_summary']['rewards_count']);$this->assertSame($reward->gold_amount,$tick['session_pending_rewards_summary']['gold_amount']);$this->assertSame($reward->experience_amount,$tick['session_pending_rewards_summary']['experience_amount']);$this->assertSame((int)HuntRewardItem::sum('quantity'),$tick['character_pending_rewards_summary']['total_quantity']);foreach(HuntRewardItem::all() as $line)$this->assertSame($line->huntEnemy->instance_identifier,$line->source_instance_identifier);}
 public function test_early_tick_has_null_generated_reward_and_does_not_duplicate(){$c=$this->player();$service=app(HuntingSessionService::class);$s=HuntingSession::find($service->start($c,$this->zone())->id());$service->tick($c,$s);$reward=HuntReward::first();$lines=HuntRewardItem::count();$early=$service->tick($c,$s)->toArray();$this->assertNull($early['generated_reward']);$this->assertSame(1,HuntReward::count());$this->assertSame($lines,HuntRewardItem::count());$this->assertSame($reward->generated_at->toDateTimeString(),$reward->fresh()->generated_at->toDateTimeString());}
 public function test_empty_reward_is_idempotent_and_manual_hunt_has_none(){MonsterLootEntry::query()->update(['drop_chance_basis_points'=>1]);$c=$this->player();$service=app(HuntingSessionService::class);$s=HuntingSession::find($service->start($c,$this->zone())->id());$service->tick($c,$s);$reward=HuntReward::first();$this->assertNotNull($reward);$this->assertSame(0,$reward->items()->count());DB::transaction(function()use($reward,$s){$a=app(HuntRewardService::class)->generatePendingForLockedHunt($reward->hunt_id,$s->id);$b=app(HuntRewardService::class)->generatePendingForLockedHunt($reward->hunt_id,$s->id);$this->assertSame($a->rewardId(),$b->rewardId());});$manual=app(HuntService::class)->start($this->player(),$this->zone());$this->assertNull(Hunt::find($manual->huntId())->reward);}
 public function test_schema_unique_and_delete_policies(){$rules=DB::select("SELECT TABLE_NAME,DELETE_RULE FROM information_schema.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA=DATABASE() AND TABLE_NAME IN ('hunt_rewards','hunt_reward_items')");$this->assertCount(5,$rules);$indexes=DB::select("SHOW INDEX FROM hunt_rewards WHERE Key_name='hunt_rewards_hunt_id_unique'");$this->assertNotEmpty($indexes);}
}
